define(["core/ajax"],(function(o){return{getUserOtopo:async function(t,e){var s=o.call([{methodname:"mod_otopo_get_user_otopo",args:{otopo:t,session:e}}]);return await s[0]},setUserOtopo:async function(t,e,s,a,n){var r=o.call([{methodname:"mod_otopo_set_user_otopo",args:{otopo:t,session:e,item:s,degree:a,justification:n}}]);await r[0]},getSessions:async function(t){var e=o.call([{methodname:"mod_otopo_get_sessions",args:{otopo:t}}]);return await e[0]}}}));